const invoiceRows = $input.all().map(i => i.json);
const miscRows = $('Query Misc Expenses').all().map(i => i.json);
const activeMisc = miscRows.filter(r => r.status !== 'cancelled');

const totalMisc      = activeMisc.reduce((s, r) => s + Number(r.amount || 0), 0);
const totalFacturado = invoiceRows.reduce((s, r) => s + Number(r.total || 0), 0);
const totalPagado    = invoiceRows.reduce((s, r) => s + Number(r.paid_amount || 0), 0);
const totalDeuda     = invoiceRows.reduce((s, r) => s + Number(r.pending_amount || 0), 0);

// by_category (misc)
const catMap = {};
for (const r of activeMisc) {
  const cat = r.category_name || 'Sin categoría';
  catMap[cat] = (catMap[cat] || 0) + Number(r.amount || 0);
}
const by_category = Object.entries(catMap)
  .sort((a, b) => b[1] - a[1])
  .map(([category, amount]) => ({ category, amount, pct: totalMisc ? Number((amount / totalMisc * 100).toFixed(1)) : 0 }));

// by_supplier (invoices)
const suppMap = {};
for (const r of invoiceRows) {
  const key = r.supplier_id || r.supplier_name || 'desconocido';
  if (!suppMap[key]) suppMap[key] = { supplier_id: r.supplier_id || '', supplier_name: r.supplier_name || 'Sin proveedor', rut: r.supplier_rut || null, total: 0, paid: 0, pending: 0, invoices: 0 };
  suppMap[key].total   += Number(r.total || 0);
  suppMap[key].paid    += Number(r.paid_amount || 0);
  suppMap[key].pending += Number(r.pending_amount || 0);
  suppMap[key].invoices++;
}
const by_supplier = Object.values(suppMap).sort((a, b) => b.total - a.total);
const by_supplier_debt = [...by_supplier].filter(s => s.pending > 0).sort((a, b) => b.pending - a.pending);

// by_period (stacked misc + facturas)
const periodMap = {};
for (const r of activeMisc) {
  const p = (r.date || '').substring(0, 10);
  if (!periodMap[p]) periodMap[p] = { misc: 0, facturas: 0 };
  periodMap[p].misc += Number(r.amount || 0);
}
for (const r of invoiceRows) {
  const p = (r.date || '').substring(0, 10);
  if (!periodMap[p]) periodMap[p] = { misc: 0, facturas: 0 };
  periodMap[p].facturas += Number(r.total || 0);
}
const by_period = Object.entries(periodMap)
  .sort((a, b) => a[0].localeCompare(b[0]))
  .map(([periodo, d]) => ({ periodo, misc: d.misc, facturas: d.facturas, total: d.misc + d.facturas }));

// by_service (top services in supplier invoices)
const svcMap = {};
for (const r of invoiceRows) {
  if (!r.top_service) continue;
  svcMap[r.top_service] = (svcMap[r.top_service] || 0) + Number(r.total || 0);
}
const by_service = Object.entries(svcMap)
  .sort((a, b) => b[1] - a[1]).slice(0, 10)
  .map(([service, amount]) => ({ service, amount }));

// by_payment_state
const stateMap = {};
for (const r of invoiceRows) {
  const st = r.payment_state || 'unpaid';
  if (!stateMap[st]) stateMap[st] = { count: 0, total: 0 };
  stateMap[st].count++;
  stateMap[st].total += Number(r.total || 0);
}
const by_payment_state = Object.entries(stateMap)
  .map(([state, d]) => ({ state, ...d }));

return [{ json: {
  summary: {
    total_misc: totalMisc, total_facturado: totalFacturado,
    total_pagado: totalPagado, total_deuda: totalDeuda,
    num_misc: miscRows.length, num_invoices: invoiceRows.length,
    top_category: by_category[0]?.category || '',
    top_supplier: by_supplier[0]?.supplier_name || '',
    top_debtor:   by_supplier_debt[0]?.supplier_name || ''
  },
  by_category, by_supplier, by_supplier_debt, by_period, by_service, by_payment_state,
  misc_rows: miscRows, invoice_rows: invoiceRows
} }];
